import { useState, useEffect } from 'react';
import { Routes, Route } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';
import { useAudio } from './hooks/useAudio';
import { useTables } from './hooks/useTables';
import { useInventory } from './hooks/useInventory';
import { CardProvider } from './contexts/CardContext';
import Login from './components/Login';
import Header from './components/Header';
import TableGrid from './components/TableGrid';
import StatusDashboard from './components/StatusDashboard';
import ShoppingList from './components/ShoppingList';
import ActivityLog from './components/ActivityLog';
import RequirementsCard from './components/RequirementsCard';
import FeaturesCard from './components/FeaturesCard';
import FooterLinks from './components/FooterLinks';
import AdminPanel from './components/AdminPanel';
import Manual from './components/Manual';
import Inventory from './components/Inventory';
import MultiPage1 from './components/MultiPage1';
import getAppVersionInfo from './versionInfo'; // Import the version info module

import { useSettings } from './hooks/useSettings';

function App() {
  const { user, userData, loading, loginEmail, loginAnonymously, logout } = useAuth();
  const { tables } = useTables();
  const { inventory } = useInventory();
  const { settings } = useSettings();
  const { isAudioEnabled, initAudio, playNotificationSound } = useAudio(tables, inventory, settings);
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [titleSuffix, setTitleSuffix] = useState('');
  const appVersionInfo = getAppVersionInfo(); // Get the app version information

  useEffect(() => {
    const env = import.meta.env.MODE;
    let suffix = '';
    if (env === 'development') {
      suffix = ' [DEV]';
    } else if (env === 'staging') {
      suffix = ' [STAGING]';
    }
    document.title += suffix;
    setTitleSuffix(suffix);
  }, []);

  // ÉTAPE 1 : Attendre que Firebase réponde
  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center">
        <div className="text-[#d4af37] animate-pulse font-bold uppercase tracking-[0.3em]">
          Mictlán...
        </div>
      </div>
    );
  }

  // ÉTAPE 2 : Si pas d'utilisateur, on force l'affichage du Login uniquement
  if (!user) {
    return <Login onLogin={loginEmail} onAnonymousLogin={loginAnonymously} />;
  }

  // ÉTAPE 3 : Si connecté, on affiche le Dashboard
  return (
    <div className="min-h-screen bg-[#0a0a0a] text-gray-200">
      <Header user={user} onLogout={logout} isAudioEnabled={isAudioEnabled} onEnableAudio={initAudio} titleSuffix={titleSuffix} />
      <Manual userData={userData} />
      <CardProvider>
        <Routes>
          <Route path="/" element={
            <main className="container mx-auto py-8 flex flex-col gap-12 px-4">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <TableGrid playNotificationSound={playNotificationSound} />
                <StatusDashboard />
                <Inventory user={user} />
                <ShoppingList />
                <ActivityLog />
              </div>
              <FooterLinks versionInfo={appVersionInfo.fullVersion} /> {/* Pass version info to FooterLinks */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {userData?.role === 'admin' && <AdminPanel />}
                {userData?.role === 'admin' && <FeaturesCard />}
                {userData?.role === 'admin' && <RequirementsCard />}
              </div>
            </main>
          } />
          <Route path="/multipage1" element={<MultiPage1 />} />
        </Routes>
      </CardProvider>
    </div>
  );
}

export default App;

import { useState } from 'react';
import * as Tone from 'tone';
import { Activity, BellRing } from 'lucide-react';
import Card from './Card';

const alertStates = {
  personnel: {
    ok: { name: "Personnel", status: "Optimal", color: "text-green-500" },
    alarm: { name: "Personnel", status: "Critique", color: "text-red-500" }
  },
  waitTime: {
    ok: { name: "Temps d'Attente", status: "Normal", color: "text-green-500" },
    alarm: { name: "Temps d'Attente", status: "Élevé", color: "text-orange-500" }
  },
  reviews: {
    ok: { name: "Avis en Ligne", status: "OK", color: "text-green-500" },
    alarm: { name: "Avis en Ligne", status: "Négatif Reçu", color: "text-red-500" }
  }
};

export default function StatusDashboard() {
  const [indicators, setIndicators] = useState([
    { id: 'personnel', ...alertStates.personnel.ok, isAlarm: false },
    { id: 'waitTime', ...alertStates.waitTime.alarm, isAlarm: true },
    { id: 'reviews', ...alertStates.reviews.alarm, isAlarm: true },
  ]);

  const playAlarmSound = async () => {
    if (Tone.context.state !== 'running') {
      await Tone.start();
    }
    // Son d'alerte : Note plus grave et percutante (réutilisé de useAudio)
    const synth = new Tone.MembraneSynth().toDestination();
    synth.volume.value = -5;
    synth.triggerAttackRelease("G2", "4n");
  };
  
  const handleClick = (index) => {
    const newIndicators = [...indicators];
    const indicator = newIndicators[index];
    const newIsAlarm = !indicator.isAlarm;

    // Update the indicator with the new state
    const newState = newIsAlarm ? alertStates[indicator.id].alarm : alertStates[indicator.id].ok;
    newIndicators[index] = { ...indicator, ...newState, isAlarm: newIsAlarm };
    
    setIndicators(newIndicators);

    if (newIsAlarm) {
      playAlarmSound();
    }
  };

  return (
    <Card title="Alertes" titleIcon={<Activity />}>
      <div className="grid grid-cols-3 gap-4">
        {indicators.map((ind, i) => (
          <div 
            key={i} 
            onClick={() => handleClick(i)}
            className="p-4 bg-black/20 rounded-2xl border border-gray-800 text-center group hover:border-mictlan-gold/30 transition-all cursor-pointer"
          >
            <p className="text-[10px] font-black text-gray-500 uppercase mb-1 flex items-center justify-center">
              {ind.name}
              {ind.isAlarm && <BellRing size={12} className="ml-1.5 text-red-500 animate-wiggle" />}
            </p>
            <p className={`text-xs font-bold uppercase ${ind.color}`}>{ind.status}</p>
          </div>
        ))}
      </div>
    </Card>
  );
}

import { CheckCircle2, ListChecks } from 'lucide-react';
import Card from './Card'; // Assuming Card is the component name

export default function FeaturesCard() {
  const features = [
    { name: "Toggles Waiter/Bill/TPE", date: "2025-12-30" },
    { name: "Mode Double Grid", date: "2025-12-30" }
  ];

  return (
    <Card title="Features" titleIcon={<ListChecks />}>
      <div className="space-y-3">
        {features.map((f, i) => (
          <div key={i} className="flex items-center justify-between p-4 bg-black/20 rounded-xl border border-gray-800/50">
            <div className="flex items-center gap-3">
              <CheckCircle2 size={14} className="text-mictlan-gold" />
              <span className="text-[11px] font-bold text-gray-400 uppercase">{f.name}</span>
            </div>
            <span className="text-[9px] font-black text-gray-600">{f.date}</span>
          </div>
        ))}
      </div>
    </Card>
  );
}

